guild_${GUILD_ID}.playlistItemsFull.aggregate([
  {
    // Match documents where `added_at` is a string
    "$match": {
      "added_at": {
        "$type": "string"
      }
    }
  },
  {
    // Perform a users to join with the `users` collection
    "$lookup": {
      "from": "users",
      "localField": "added_by",
      "foreignField": "_id",
      "as": "addedByDetails"
    }
  },
  {
    // Flatten the result of the users and handle null values
    "$addFields": {
      "addedByDetails": {
        "$arrayElemAt": ["$addedByDetails", 0]
      }
    }
  },
  {
    // Match documents where `addedByDetails.display_name` is not null, empty, or "Tom"
    "$match": {
      "addedByDetails.display_name": {
        "$nin": [null, "", "Tom"]
      }
    }
  },
  {
    // Convert `added_at` from string to date
    "$addFields": {
      "added_at": {
        "$convert": {
          "input": "$added_at",
          "to": "date",
          "onError": null,
          "onNull": null
        }
      }
    }
  },
  {
    // Match documents where `added_at` is successfully converted to a date
    "$match": {
      "added_at": {
        "$type": "date"
      }
    }
  },
  {
    // Extract the year and month from `added_at` in the "Europe/Paris" timezone
    "$addFields": {
      "monthYear": {
        "$dateToString": {
          "format": "%Y-%m",
          "date": "$added_at",
          "timezone": "Europe/Paris"
        }
      }
    }
  },
  {
    // Group by `monthYear` and `addedByDetails.display_name`, and count the number of documents in each group
    "$group": {
      "_id": {
        "monthYear": "$monthYear",
        "name": "$addedByDetails.display_name"
      },
      "count": {
        "$sum": 1
      }
    }
  },
  {
    // Project the desired fields for the final output
    "$project": {
      "_id": 0,
      "monthYear": "$_id.monthYear",
      "name": "$_id.name",
      "count": 1
    }
  },
  {
    // Sort the documents by `monthYear` in ascending order
    "$sort": {
      "monthYear": 1
    }
  }
])

guild_${GUILD_ID}.votes.aggregate([
  {
    $match: {
      "votes.$person": {
        $exists: true,
      },
    },
  },
   {
    $set: {
      date: {
        $dateFromString: {
          dateString: "$date",
        },
      },
    },
  },
  {
        $match: {
            date: {
                $gt: ISODate("${__from:date:iso}"),
                $lt: ISODate("${__to:date:iso}")
            }
        }
    },
  {
    $project: {
      _id: 0,
      date: 1,
      name: 1,
      state: 1,
      vote: "$votes.$person",
    },
  },
])

