guild_${GUILD_ID}.votes.aggregate([
  {
    $match: {
      "votes.$person": {
        $exists: true,
      }, // Filter documents where the person voted
    },
  },
  {
    $set: {
      date: {
        $dateFromString: {
          dateString: "$date",
        },
      },
    },
  },
  {
        $match: {
            date: {
                $gt: ISODate("${__from:date:iso}"),
                $lt: ISODate("${__to:date:iso}")
            }
        }
    },
  {
    $group: {
      _id: {
        date: "$date",
      },
      menfouTotal: {
        $sum: {
          $cond: [
            {
              $eq: [
                "$votes.$person",
                "menfou",
              ],
            },
            1,
            0,
          ],
        },
      },
      supprimerTotal: {
        $sum: {
          $cond: [
            {
              $eq: [
                "$votes.$person",
                "supprimer",
              ],
            },
            1,
            0,
          ],
        },
      },
      conserverTotal: {
        $sum: {
          $cond: [
            {
              $eq: [
                "$votes.$person",
                "conserver",
              ],
            },
            1,
            0,
          ],
        },
      },
    },
  },
  {
    $sort: {
      "_id.date": 1,
    },
  },
  {
    $setWindowFields: {
      partitionBy: "$_id.person",
      sortBy: {
        "_id.date": 1,
      },
      output: {
        menfouTotal: {
          $sum: "$menfouTotal",
          window: {
            documents: ["unbounded", "current"],
          },
        },
        supprimerTotal: {
          $sum: "$supprimerTotal",
          window: {
            documents: ["unbounded", "current"],
          },
        },
        conserverTotal: {
          $sum: "$conserverTotal",
          window: {
            documents: ["unbounded", "current"],
          },
        },
      },
    },
  },
  {
    $project: {
      _id: 0,
      date: "$_id.date",
      menfouTotal: 1,
      supprimerTotal: 1,
      conserverTotal: 1,
    },
  },
])

